body.script:
window.dataLayer = window.dataLayer || [];
function gtag() {dataLayer.push(arguments);}
gtag('js', new Date());
gtag('config', 'G-NQ3WX8KNQW');

const gmes_search = document.getElementById("gmes_search");
const opengme = (file_name, title, frame) => {
  fetch(`https://raw.githubusercontent.com/Hydra-Network/hydra-assets/main/gmes/${file_name}?t=${Date.now()}`)
    .then(response => response.text())
    .then(html => {
      const newWin = window.open("about:blank", "_blank");
      if (newWin) {
        newWin.document.open();
        newWin.document.write(html);
        newWin.document.close();
      } else {
        alert("Popup blocked!");
      }
    })
    .catch(err => console.error(err));
};
gmes_search.addEventListener("input", e => {
  const query = e.target.value.toLowerCase();
  document.querySelectorAll(".card").forEach(card => {
    card.style.display = card.dataset.title.toLowerCase().includes(query) ? "" : "none";
  });
});
